[asy]
import three;
currentprojection = orthographic(1.5,1.1,-1);
triple A = (1,1,1);
triple B = (1,0,0);
triple C = (0,1,0);
triple D = (0,0,1);
draw(A--B--C--A);
draw(A--D,dashed);
